import{f as d,D as E,o as a,c as g,a2 as r,b as l,w as o,a as s,G as i,a5 as n}from"./chunks/framework.DHYrF-q6.js";const C=JSON.parse('{"title":"高并发设计模式总览","description":"","frontmatter":{},"headers":[],"relativePath":"high-concurrency/design-patterns/index.md","filePath":"high-concurrency/design-patterns/index.md","lastUpdated":1780917900000}'),A={name:"high-concurrency/design-patterns/index.md"};function u(h,t,p,B,q,c){const e=E("Mermaid");return a(),g("div",null,[t[2]||(t[2]=r('<h1 id="高并发设计模式总览" tabindex="-1">高并发设计模式总览 <a class="header-anchor" href="#高并发设计模式总览" aria-label="Permalink to &quot;高并发设计模式总览&quot;">​</a></h1><p>创建日期：2026-06-06</p><h2 id="模块概述" tabindex="-1">模块概述 <a class="header-anchor" href="#模块概述" aria-label="Permalink to &quot;模块概述&quot;">​</a></h2><p>高并发设计模式是解决系统在高流量场景下保持可用性、稳定性和性能的&quot;兵器库&quot;。本模块从<strong>流量控制</strong>、<strong>缓存加速</strong>、<strong>异步解耦</strong>三个维度，系统讲解 4 种最核心的高并发设计模式，帮助你在面试中能够清晰阐述每种模式的适用场景、实现原理和选型对比。</p><div class="tip custom-block"><p class="custom-block-title">核心思想</p><p>高并发设计的本质不是消除并发，而是<strong>将并发控制在系统可承受范围内</strong>，同时通过空间换时间、异步换吞吐等手段，提升系统整体处理能力。</p></div><h2 id="设计模式全景图" tabindex="-1">设计模式全景图 <a class="header-anchor" href="#设计模式全景图" aria-label="Permalink to &quot;设计模式全景图&quot;">​</a></h2>',6)),(a(),l(n,null,{default:o(()=>[i(e,{id:"mermaid-20",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20A%5B%E9%AB%98%E5%B9%B6%E5%8F%91%E6%8C%91%E6%88%98%5D%20--%3E%20B%5B%E6%B5%81%E9%87%8F%E6%8E%A7%E5%88%B6%5D%0A%20%20%20%20A%20--%3E%20C%5B%E7%BC%93%E5%AD%98%E5%8A%A0%E9%80%9F%5D%0A%20%20%20%20A%20--%3E%20D%5B%E5%BC%82%E6%AD%A5%E8%A7%A3%E8%80%A6%5D%0A%0A%20%20%20%20B%20--%3E%20B1%5B%E9%99%90%E6%B5%81%E7%AE%97%E6%B3%95%3Cbr%2F%3Erate-limiter%5D%0A%20%20%20%20B%20--%3E%20B2%5B%E9%99%8D%E7%BA%A7%E7%86%94%E6%96%AD%3Cbr%2F%3Ecircuit-breaker%5D%0A%0A%20%20%20%20C%20--%3E%20C1%5B%E7%BC%93%E5%AD%98%E7%AD%96%E7%95%A5%3Cbr%2F%3Ecaching%5D%0A%0A%20%20%20%20D%20--%3E%20D1%5B%E5%BC%82%E6%AD%A5%E5%A4%84%E7%90%86%3Cbr%2F%3Easync%5D%0A%0A%20%20%20%20style%20B%20fill%3A%23e3f2fd%2Cstroke%3A%232196f3%0A%20%20%20%20style%20C%20fill%3A%23e8f5e9%2Cstroke%3A%234caf50%0A%20%20%20%20style%20D%20fill%3A%23fff3e0%2Cstroke%3A%23ff9800%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=r('<h2 id="各模式核心问题" tabindex="-1">各模式核心问题 <a class="header-anchor" href="#各模式核心问题" aria-label="Permalink to &quot;各模式核心问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>解决什么问题</th><th>核心思想</th><th>典型场景</th></tr></thead><tbody><tr><td><strong>限流</strong></td><td>请求突刺冲垮系统</td><td>控制单位时间请求量，超过阈值直接拒绝</td><td>API 网关、开放平台、秒杀入口</td></tr><tr><td><strong>熔断降级</strong></td><td>依赖服务故障扩散</td><td>快速失败 + 降级兜底，防止故障扩散</td><td>微服务调用链、第三方依赖</td></tr><tr><td><strong>缓存策略</strong></td><td>读请求打垮数据库</td><td>空间换时间，热点数据加速，减少 DB 压力</td><td>商品详情、首页推荐、配置数据</td></tr><tr><td><strong>异步处理</strong></td><td>同步等待浪费资源</td><td>削峰填谷，解耦非关键链路，提升吞吐</td><td>下单、通知、日志、统计</td></tr></tbody></table><h2 id="设计模式选型决策树" tabindex="-1">设计模式选型决策树 <a class="header-anchor" href="#设计模式选型决策树" aria-label="Permalink to &quot;设计模式选型决策树&quot;">​</a></h2>',3)),(a(),l(n,null,{default:o(()=>[i(e,{id:"mermaid-103",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%22%E7%B3%BB%E7%BB%9F%E9%81%87%E5%88%B0%E4%BB%80%E4%B9%88%E9%97%AE%E9%A2%98%EF%BC%9F%22%5D%20--%3E%20B%7B%22%E7%9E%AC%E6%97%B6%E6%B5%81%E9%87%8F%E8%BF%87%E5%A4%A7%EF%BC%9F%22%7D%0A%20%20%20%20B%20--%3E%7C%E6%98%AF%7C%20C%5B%22%E2%9C%85%20%E9%99%90%E6%B5%81%E7%AE%97%E6%B3%95%22%5D%0A%20%20%20%20B%20--%3E%7C%E5%90%A6%7C%20D%7B%22%E4%BE%9D%E8%B5%96%E6%9C%8D%E5%8A%A1%E4%B8%8D%E7%A8%B3%E5%AE%9A%EF%BC%9F%22%7D%0A%20%20%20%20D%20--%3E%7C%E6%98%AF%7C%20E%5B%22%E2%9C%85%20%E7%86%94%E6%96%AD%E9%99%8D%E7%BA%A7%22%5D%0A%20%20%20%20D%20--%3E%7C%E5%90%A6%7C%20F%7B%22%E6%95%B0%E6%8D%AE%E5%BA%93%E6%89%9B%E4%B8%8D%E4%BD%8F%E8%AF%BB%EF%BC%9F%22%7D%0A%20%20%20%20F%20--%3E%7C%E6%98%AF%7C%20G%5B%22%E2%9C%85%20%E7%BC%93%E5%AD%98%E7%AD%96%E7%95%A5%22%5D%0A%20%20%20%20F%20--%3E%7C%E5%90%A6%7C%20H%7B%22%E5%90%8C%E6%AD%A5%E7%AD%89%E5%BE%85%E5%A4%AA%E6%85%A2%EF%BC%9F%22%7D%0A%20%20%20%20H%20--%3E%7C%E6%98%AF%7C%20I%5B%22%E2%9C%85%20%E5%BC%82%E6%AD%A5%E5%A4%84%E7%90%86%22%5D%0A%20%20%20%20H%20--%3E%7C%E5%90%A6%7C%20J%5B%22%E7%BB%A7%E7%BB%AD%E6%8E%92%E6%9F%A5%E5%85%B6%E4%BB%96%E7%93%B6%E9%A2%88%22%5D%0A%0A%20%20%20%20style%20C%20fill%3A%23e8f5e9%2Cstroke%3A%234caf50%0A%20%20%20%20style%20E%20fill%3A%23e8f5e9%2Cstroke%3A%234caf50%0A%20%20%20%20style%20G%20fill%3A%23e8f5e9%2Cstroke%3A%234caf50%0A%20%20%20%20style%20I%20fill%3A%23e8f5e9%2Cstroke%3A%234caf50%0A"})]),fallback:o(()=>[...t[1]||(t[1]=[s(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=r('<h2 id="面试考察重点" tabindex="-1">面试考察重点 <a class="header-anchor" href="#面试考察重点" aria-label="Permalink to &quot;面试考察重点&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">高频考点</p><ol><li><strong>限流算法对比</strong>：计数器、滑动窗口、漏桶、令牌桶各自优缺点是什么？什么场景选什么？</li><li><strong>熔断器三态</strong>：Closed → Open → Half-Open 状态流转是什么？慢调用和异常比例哪个更准确？</li><li><strong>缓存更新</strong>：Cache Aside vs Write Behind vs Write Through，画图说明读写流程</li><li><strong>缓存一致性</strong>：先删缓存还是先更新数据库？延迟双删原理是什么？</li><li><strong>CompletableFuture</strong>：如何用它编排多个异步任务？allOf vs anyOf 区别？</li><li><strong>舱壁隔离</strong>：线程池隔离和信号量隔离有什么区别？什么时候用什么？</li></ol></div><div class="danger custom-block"><p class="custom-block-title">容易翻车的点</p><ul><li>把单机方案直接用到分布式场景，漏掉分布式环境需要考虑的问题</li><li>只说概念不说具体实现，不能说出框架（Guava/Sentinel/Resilience4j）的具体用法</li><li>忽略异常处理和降级兜底，设计出来的系统不可用</li><li>选型不看场景，盲目追新技术</li><li>混淆限流、降级、熔断三个概念，答非所问</li></ul></div><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to &quot;学习路径建议&quot;">​</a></h2><ol><li><strong>先理解问题</strong>：每种模式解决的痛点是什么？不这么做会有什么后果？</li><li><strong>对比算法</strong>：不同算法实现思路有什么差异？时间空间复杂度如何？</li><li><strong>落地实现</strong>：了解主流框架的实现，能说出核心配置和坑点</li><li><strong>画图总结</strong>：把每种模式的流程图画出来，形成肌肉记忆</li><li><strong>模拟面试</strong>：用自己的话把每种模式讲清楚，不要背概念</li></ol><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>《大型网站技术架构：核心原理与案例分析》—— 李智慧</li><li>《亿级流量网站架构核心技术》—— 张开涛</li><li><a href="https://sentinelguard.io/" target="_blank" rel="noreferrer">Sentinel 官方文档</a></li><li><a href="https://resilience4j.readme.io/" target="_blank" rel="noreferrer">Resilience4j 官方文档</a></li><li><a href="https://github.com/google/guava/wiki" target="_blank" rel="noreferrer">Guava RateLimiter 文档</a></li></ul><hr><h2 id="经典高频面试题" tabindex="-1">经典高频面试题 <a class="header-anchor" href="#经典高频面试题" aria-label="Permalink to &quot;经典高频面试题&quot;">​</a></h2><h3 id="q1-高并发系统设计中-限流、降级、熔断三个概念有什么区别" tabindex="-1">Q1：高并发系统设计中，限流、降级、熔断三个概念有什么区别？ <a class="header-anchor" href="#q1-高并发系统设计中-限流、降级、熔断三个概念有什么区别" aria-label="Permalink to &quot;Q1：高并发系统设计中，限流、降级、熔断三个概念有什么区别？&quot;">​</a></h3><p><strong>知识要点：</strong> 限流控制入口流量，降级保证核心可用，熔断防止故障扩散。三个概念经常配合使用。</p><table tabindex="0"><thead><tr><th>概念</th><th>作用时机</th><th>解决问题</th><th>目标</th></tr></thead><tbody><tr><td><strong>限流</strong></td><td>入口处</td><td>防止总流量超过系统承载能力</td><td>保护整个系统，拒绝超限请求</td></tr><tr><td><strong>降级</strong></td><td>业务执行时</td><td>非核心链路出问题时保证核心可用</td><td>牺牲非核心功能，保障核心链路</td></tr><tr><td><strong>熔断</strong></td><td>依赖调用时</td><td>防止下游故障导致本系统资源耗尽</td><td>快速失败，防止故障扩散</td></tr></tbody></table><p><strong>项目场景：</strong> 我们双十一大促系统，这三样东西全用上了，少了哪个都会出问题。</p><p><strong>踩坑经历：</strong> 限流把流量挡在门外没问题，但有一次限流阈值设太保守（5000 QPS），实际系统能扛 8000 QPS。多余的 3000 个用户全部看到&quot;系统繁忙&quot;，但其实系统很空闲。降级也有坑——有一次把&quot;优惠券查询&quot;降级了，结果用户下单时优惠券没生效，后续客诉处理花了 2 个客服一整天。熔断最坑的一次是熔断恢复太慢，支付服务恢复了 10 分钟熔断器还没打开，白白丢了订单。</p><p><strong>决策过程：</strong> 限流阈值用压测确定（压测极限 × 0.7），上线后监控一周再微调。降级要精确到功能粒度而非服务粒度——优惠券服务可以不调优惠列表，但下单时的优惠券校验不能降。熔断要配半开探测，恢复后 30 秒内自动切回。</p><p><strong>量化结果：</strong> 三件套配齐后，双十一大促核心链路零故障，99.99% 的可用性。即使有 2 个下游服务同时故障，用户依然能完成下单支付。</p><p><strong>面试官追问：</strong></p><ol><li>限流、降级、熔断三者在请求链路上的执行顺序是什么？</li><li>如果都要做，哪个先做哪个后做？有没有推荐的优先级？</li><li>这三个概念在实际代码里怎么体现？能画个简化的流程图吗？</li></ol><h3 id="q2-为什么高并发系统需要设计模式-直接堆机器不行吗" tabindex="-1">Q2：为什么高并发系统需要设计模式？直接堆机器不行吗？ <a class="header-anchor" href="#q2-为什么高并发系统需要设计模式-直接堆机器不行吗" aria-label="Permalink to &quot;Q2：为什么高并发系统需要设计模式？直接堆机器不行吗？&quot;">​</a></h3><p><strong>知识要点：</strong> 设计模式是从架构层面解决根本性问题，堆机器解决不了热点集中、数据一致性、资源竞争等问题。</p><p><strong>项目场景：</strong> 我们公司最初创业时，日活 10 万，一台 4C8G 服务器搞定。后来日活涨到 500 万，CTO 说&quot;加机器&quot;，从 1 台加到 20 台，结果还是扛不住。</p><p><strong>踩坑经历：</strong> 加机器没有解决任何实质问题。库存超卖还是超卖（因为单机 Redis 变多机 Redis，分布式锁没跟上）；热点商品还是打爆了 MySQL（因为缓存没做本地缓存，所有机器都穿透到同一台 MySQL）；限流还是不行（因为每台机器自己限 500 QPS，20 台 = 10000 QPS，下游早被打穿了）。</p><p><strong>决策过程：</strong> 不是不加机器，而是先搞清问题本质。超卖→分布式锁+Redis 原子操作；热点→本地缓存+多级缓存；限流失效→分布式限流 Sentinel。架构问题用设计模式解决，容量问题用机器解决。</p><p><strong>量化结果：</strong> 架构改造后，同样 20 台机器，支撑的用户量从 500 万涨到 2000 万。扩容成本从之前&quot;每加 100 万用户加 5 台机器&quot;变成&quot;每加 500 万用户加 5 台机器&quot;。架构优化带来的成本节省每年约 50 万服务器费用。</p><p><strong>面试官追问：</strong></p><ol><li>怎么判断一个性能问题是架构问题还是单纯的容量不足？</li><li>创业早期，资源有限，你会优先投入哪个高并发设计模式？</li><li>水平扩容有上限吗？什么情况下再加机器也没用了？</li></ol><h3 id="q3-高并发设计中-空间换时间-和-时间换空间-各自什么时候用" tabindex="-1">Q3：高并发设计中，&quot;空间换时间&quot;和&quot;时间换空间&quot;各自什么时候用？ <a class="header-anchor" href="#q3-高并发设计中-空间换时间-和-时间换空间-各自什么时候用" aria-label="Permalink to &quot;Q3：高并发设计中，&quot;空间换时间&quot;和&quot;时间换空间&quot;各自什么时候用？&quot;">​</a></h3><p><strong>知识要点：</strong> 高并发读多用空间换时间（缓存、预计算），存储容量敏感多用时间换空间（压缩、按需计算）。</p><p><strong>项目场景：</strong> 我们商品详情页，每天 2 亿次访问，QPS 峰值 8000。商品数据存在 MySQL，每次查 RT 200ms，根本扛不住。</p><p><strong>踩坑经历：</strong> 没做缓存的时候（纯空间换时间），MySQL 只存 50 万商品，磁盘使用 20GB，但 QPS 只能到 500。后来全量缓存到 Redis（空间换时间），50 万商品在 Redis 占约 8GB 内存，QPS 提到 8000，RT 降到 5ms。但随之而来的是 Redis 成本——8GB × 主从 × 集群 ≈ 每月 3000 元。</p><p><strong>决策过程：</strong> 我们对商品做了冷热分离。核心 5 万热商品全量缓存 Redis（约 800MB），剩余 45 万冷商品用&quot;按需加载+LRU 淘汰+较短过期&quot;，平均在 Redis 只占 2GB。这样空间换时间用在了刀刃上（热点），冷门商品用时间换空间（按需查 DB，多等一会儿）。</p><p><strong>量化结果：</strong> Redis 内存需求从 8GB 降到 3GB，成本降低 60%，缓存命中率从 99.2% 降到 97.5%（冷商品不常缓存），整体 RT 从 5ms 变 8ms，仍然远低于 50ms 的 SLA 目标。</p><p><strong>面试官追问：</strong></p><ol><li>冷热分离的冷热标准是什么？怎么动态调整？</li><li>时间换空间的极致就是不做缓存每次都查 DB，你怎么找到缓存比例的最佳平衡点？</li><li>除了缓存，还有哪些空间换时间/时间换空间的典型例子？</li></ol><h3 id="q4-舱壁隔离-bulkhead-模式是什么-解决什么问题" tabindex="-1">Q4：舱壁隔离（Bulkhead）模式是什么？解决什么问题？ <a class="header-anchor" href="#q4-舱壁隔离-bulkhead-模式是什么-解决什么问题" aria-label="Permalink to &quot;Q4：舱壁隔离（Bulkhead）模式是什么？解决什么问题？&quot;">​</a></h3><p><strong>知识要点：</strong> 把不同业务的资源（线程池/连接池）物理隔离，一个业务的故障不拖垮其他业务。</p><p><strong>项目场景：</strong> 我们的订单服务同时提供&quot;创建订单&quot;和&quot;查询订单&quot;两个接口。创建订单慢（需要调多个下游），查询订单快（只读缓存）。</p><p><strong>踩坑经历：</strong> 大促时大量创建订单请求占满了 Tomcat 200 个线程，用户想点&quot;我的订单&quot;查看结果，发现页面打不开——因为查询订单的请求也被阻塞了，线程池全被创建订单占着。用户以为订单丢了，重复下单，又加重了创建订单的压力。</p><p><strong>决策过程：</strong> 拆成两个独立的业务线程池：创建订单 80 个线程，查询订单 120 个线程。创建订单满了只影响创建，用户还是能查询自己的订单。对于本地缓存查询这种 1ms 就返回的操作，用信号量隔离（限并发数），不额外创建线程。</p><p><strong>量化结果：</strong> 线程池拆分后，即使创建订单超时率 30%，查询订单接口的 RT 仍保持 10ms 以内，零超时。用户投诉&quot;查不到订单&quot;从每天 100+ 降到 2 起以内。</p><p><strong>面试官追问：</strong></p><ol><li>舱壁隔离和熔断有什么区别？能用舱壁代替熔断吗？</li><li>线程池隔离后，怎么监控每个线程池的健康状态？线程池满了怎么告警？</li><li>如果把舱壁隔离做到极致（每个接口一个线程池），会有什么问题？</li></ol><h3 id="q5-高并发设计中-fail-fast-和-fail-safe-有什么区别" tabindex="-1">Q5：高并发设计中，&quot;Fail-Fast&quot;和&quot;Fail-Safe&quot;有什么区别？ <a class="header-anchor" href="#q5-高并发设计中-fail-fast-和-fail-safe-有什么区别" aria-label="Permalink to &quot;Q5：高并发设计中，&quot;Fail-Fast&quot;和&quot;Fail-Safe&quot;有什么区别？&quot;">​</a></h3><p><strong>知识要点：</strong> Fail-Fast 是快速失败不消耗资源，Fail-Safe 是故障后仍安全返回兜底。前者用于保护系统，后者用于保证体验。</p><p><strong>项目场景：</strong> 我们的物流查询，调第三方物流接口。第三方接口偶发性超时 5-10 秒，不能让用户等。</p><p><strong>踩坑经历：</strong> 第一次设计时既没有 Fail-Fast 也没有 Fail-Safe。物流超时 10 秒，用户等了 10 秒看到空白页。看了日志才发现是物流接口超时，返回了 500。</p><p><strong>决策过程：</strong> 加了两层。Fail-Fast：熔断器，物流接口连续失败 5 次直接打开熔断，后续请求直接失败不走物流接口，不浪费线程。Fail-Safe：降级兜底，熔断打开后返回&quot;物流信息暂不可用，请稍后查看&quot;，并展示上次查询到的缓存数据（哪怕是 1 小时前的）。</p><p><strong>量化结果：</strong> 熔断器让物流故障的影响从&quot;每个请求等 10 秒&quot;变成&quot;直接 1ms 返回降级数据&quot;，线程没有被占着等超时，其他模块完全不受影响。用户看到的是&quot;有数据但可能延迟&quot;而不是&quot;什么都没有&quot;，投诉少了很多。</p><p><strong>面试官追问：</strong></p><ol><li>Fail-Fast 和 Fail-Safe 冲突吗？能不能同时用？</li><li>如果物流接口只是变慢（5 秒），没有直接失败，你的 Fail-Fast 策略怎么处理？</li><li>有第三种策略叫&quot;Fail-Over&quot;，和这两者有什么区别？</li></ol>',50))])}const b=d(A,[["render",u]]);export{C as __pageData,b as default};
